### Step 8: `packages/pixelart/src/pixelart-provider.ts`

Provider factory + interface. Mirrors `packages/luma/src/luma-provider.ts` closely:

```typescript
import { ImageModelV3, NoSuchModelError, ProviderV3 } from '@ai-sdk/provider';
import { FetchFunction, loadApiKey, withoutTrailingSlash, withUserAgentSuffix } from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import { PixelArtImageModelId } from './pixelart-image-settings';
import { VERSION } from './version';

export interface PixelArtProviderSettings {
  apiKey?: string;       // falls back to PIXELART_API_KEY env var
  baseURL?: string;      // defaults to 'https://api.pixelart.ai/v1'
  headers?: Record<string, string>;
  fetch?: FetchFunction;
}

export interface PixelArtProvider extends ProviderV3 {
  image(modelId: PixelArtImageModelId): ImageModelV3;
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
  textEmbeddingModel(modelId: string): never;  // deprecated stub
}

const DEFAULT_BASE_URL = 'https://api.pixelart.ai/v1';

export function createPixelArt(options: PixelArtProviderSettings = {}): PixelArtProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? DEFAULT_BASE_URL);
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      baseURL: baseURL ?? DEFAULT_BASE_URL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const embeddingModel = (modelId: string) => {
    throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
  };

  return {
    specificationVersion: 'v3' as const,
    image: createImageModel,
    imageModel: createImageModel,
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
    },
    embeddingModel,
    textEmbeddingModel: embeddingModel,
  };
}

export const pixelart = createPixelArt();
```

### Step 9: `packages/pixelart/src/index.ts`

Public API surface:

```typescript
export { createPixelArt, pixelart } from './pixelart-provider';
export type { PixelArtProvider, PixelArtProviderSettings } from './pixelart-provider';
export type { PixelArtImageModelId, PixelArtImageSettings } from './pixelart-image-settings';
export type { PixelArtImageModelOptions } from './pixelart-image-model';
export { VERSION } from './version';
```

---

## Key Design Decisions

| Decision | Choice | Rationale |
|----------|--------|-----------|
| `maxImagesPerCall` | `4` | Reasonable limit; PixelArt API fictional default |
| Image response format | Base64 string (`b64_json`) | Consistent with OpenAI DALL-E pattern |
| Provider options key | `"pixelart"` | Must match provider name used in `parseProviderOptions` |
| Unsupported features | Warn for `aspectRatio`, `seed`, `files`, `mask` | PixelArt is generation-only, no editing |
| Zod version | `zod/v4` | Matches luma and other recent providers |
| `size` in providerOptions | Passthrough to `doGenerate`'s top-level `size` | SDK already provides `size` in call options, but we also allow providerOptions override for the PixelArt-specific string format |

---

