import {
  ImageModelV3,
  SharedV3Warning,
} from '@ai-sdk/provider';
import {
  FetchFunction,
  InferSchema,
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: string,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
    files,
    mask,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support the `aspectRatio` option. Use `size` instead.',
      });
    }

    if (seed != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'seed',
        details: 'PixelArt does not support the `seed` option.',
      });
    }

    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'image',
        details: 'PixelArt does not support image editing via `files`.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'image',
        details: 'PixelArt does not support mask-based inpainting.',
      });
    }

    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelartImageModelOptionsSchema,
    });

    const resolvedSize = size ?? pixelartOptions?.size ?? undefined;
    const resolvedStyle = pixelartOptions?.style ?? undefined;
    const resolvedPixelDensity = pixelartOptions?.pixelDensity ?? undefined;

    const currentDate = new Date();

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        ...(resolvedSize != null ? { size: resolvedSize } : {}),
        ...(resolvedStyle != null ? { style: resolvedStyle } : {}),
        ...(resolvedPixelDensity != null
          ? { pixel_density: resolvedPixelDensity }
          : {}),
      },
      failedResponseHandler: createJsonErrorResponseHandler({
        errorSchema: pixelartErrorSchema,
        errorToMessage: (error: PixelArtErrorData) => error.error.message,
      }),
      successfulResponseHandler: createJsonResponseHandler(
        pixelartResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(
        (item: { b64_json: string }) => item.b64_json,
      ),
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }
}

// Response schema — limited to what the implementation needs
const pixelartResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      data: z.array(
        z.object({
          b64_json: z.string(),
        }),
      ),
    }),
  ),
);

// Error schema
const pixelartErrorSchema = z.object({
  error: z.object({
    message: z.string(),
    type: z.string(),
  }),
});

type PixelArtErrorData = z.infer<typeof pixelartErrorSchema>;

/**
 * Provider options schema for PixelArt image generation.
 */
export const pixelartImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z
      .object({
        /**
         * The size of the generated image (e.g. "512x512", "1024x768").
         */
        size: z.string().nullish(),

        /**
         * The visual style of the generated image.
         * - `pixel`: Classic pixel art style
         * - `retro`: Retro/vintage aesthetic
         * - `8bit`: 8-bit video game style
         */
        style: z.enum(['pixel', 'retro', '8bit']).nullish(),

        /**
         * The pixel density of the generated image (pixels per unit).
         */
        pixelDensity: z.number().nullish(),
      })
      .passthrough(),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelartImageModelOptionsSchema
>;
